-- EXAMPLE
local on_attach = require("nvchad.configs.lspconfig").on_attach
local on_init = require("nvchad.configs.lspconfig").on_init
local capabilities = require("nvchad.configs.lspconfig").capabilities

local lspconfig = require "lspconfig"
local servers = { "html", "cssls", "clangd", "sqls", "ts_ls", "solargraph", "tailwindcss" }

-- lsps with default config
for _, lsp in ipairs(servers) do
  lspconfig[lsp].setup {
    on_attach = on_attach,
    on_init = on_init,
    capabilities = capabilities,
  }
end
-- tailwindcss
lspconfig.tailwindcss.setup {
  filetypes = {
    "erb",
    "eruby",
    "html",
    "css",
    "sass",
    "scss",
    "javascript",
    "javascriptreact",
    "typescript",
    "typescriptreact",
  },
  userLanguages = {
    eruby = "erb",
    templ = "html",
  },
}
-- typescript
lspconfig.ts_ls.setup {}
-- solargraph
lspconfig.solargraph.setup {
  filetypes = { "ruby", "eruby", "gemfile", "rakefile" },
  settings = {
    solargraph = {
      diagnostics = true,
      completion = true,
      autoformat = true,
      formatting = true,
      folding = true,
      references = true,
      rename = true,
      symbols = true,
    },
  },
}

local conform = {}

conform = {
  formatters_by_ft = {
    lua = { "stylua" },
    eruby = { "erb_format" },
    sql = { "sql_formatter" },
    javascript = { "prettierd", "prettier", stop_after_first = true },
    css = { "prettier" },
    html = { "prettier" },
    yaml = { "yamlfmt" },
  },

  -- format_on_save = {
  --   -- These options will be passed to conform.format()
  --   timeout_ms = 500,
  --   lsp_fallback = true,
  -- },
}

return conform

local treesitter = {}

treesitter.ensure_installed = {
  ensure_installed = {
    "yaml",
    "vim",
    "lua",
    "vimdoc",
    "html",
    "css",
    "embedded_template",
    "ruby",
    "sql",
    "javascript",
    "typescript",
    "tsx",
    "c",
    "markdown",
    "markdown_inline",
  },
  indent = {
    enable = true,
  },
  endwise = {
    enable = true,
  },
  embedded_template = {
    enable = true,
  },
  highlight = {
    enable = true,
  },
}

return treesitter

